п»ҝparam([string]$AccessToken,[string]$ThumbMediaId)

# Read HTML generated by wechat-article-formatter
$htmlPath="C:\Users\Administrator\.openclaw\workspace\mazda-skyactiv-article.html"
$html=Get-Content $htmlPath -Raw -Encoding UTF8

# Extract only body content (remove DOCTYPE, html, head, body tags)
$match=[regex]::Match($html,'<body[^>]*>(.*?)</body>')
if($match.Success){
    $content=$match.Groups[1].Value.Trim()
}else{
    $content=$html
}

# Remove HTML comments
$content=$content -replace '<!--.*?-->',''

# Write to temp file for verification
$content|Out-File "C:\Users\Administrator\.openclaw\workspace\content-extracted.html" -Encoding UTF8
Write-Host "Extracted content length: $($content.Length) chars"

# Escape for JSON
$content=$content -replace '\\','\\\\' -replace '"','\"'

# Build JSON
$json=@"
{"articles":[{"title":"14:1 йҗЁеӢҜз“ҹеЁүжӣӘзҙ°жӨ№о„ғеҡңжқҲжғ§оӣ§жөЈжӣ ж•ӨйҸҲвӮ¬з»—г„§ж®‘йҚҗе‘Ҝеҷ§йҸҲзғҳеҰ§йҸҲоҲӨзҙқйҚҰг„§ж•ёйҚ”г„ҰжӨӮжө пҪҶжҪғйҚ‘иҪ°з«ҙйҸүВӨо”…з’әоҲӨзҙө","author":"Nice йҚқ?,"digest":"жӨ№о„ғеҡңжқҲжғ§еһұжӨ№жӢҢж‘‘жҫ¶в•ӮеҰ§йҸҲоҲӣз№Ғжҗҙп№ҒР’йҸӢ?,"content":"$content","thumb_media_id":"$ThumbMediaId","need_open_comment":1,"only_fans_can_comment":0}]}
"@

# Publish
$url="https://api.weixin.qq.com/cgi-bin/draft/add?access_token=$AccessToken"
Write-Host "Publishing with wechat-article-formatter tech theme..."
try{
    $response=Invoke-RestMethod -Uri $url -Method Post -Body $json -ContentType "application/json; charset=utf-8"
    if($response.media_id){
        Write-Output "йүҒ?Published successfully!"
        Write-Output "Media ID: $($response.media_id)"
    }else{
        Write-Output "йүӮ?Failed: $($response.errmsg)"
    }
}catch{
    Write-Output "йүӮ?Error: $_"
}
